{
 "level": "A1–A2",
 "intro": "In this topic you will learn <strong>word order in questions and negatives</strong>: the use of auxiliary verbs, the structure of Wh-questions and common mistakes.",
 "rules": [
 {
 "label": "Yes/No questions",
 "color": "emerald",
 "text": "<strong>Do/Does/Did + Subject + Verb</strong> — basic question structure:",
 "example": "Do you like pizza?"
 },
 {
 "label": "Wh-question",
 "color": "blue",
 "text": "<strong>Wh-word + Auxiliary + Subject + Verb</strong> — question with where, what, why:",
 "example": "Where do you live?"
 },
 {
 "label": "Negation",
 "color": "amber",
 "text": "<strong>Subject + Auxiliary + not + Verb</strong> - structure of negation:",
 "example": "I don't like apples."
 }
 ]
}

{
 "title": "1. Auxiliary Verbs",
 "intro": "To construct questions and negatives, auxiliary verbs are needed:",
 "items": [
 {
 "label": "Do",
 "title": "I / You / We / They",
 "subtitle": "Do you like coffee? I do not know."
 },
 {
 "label": "Does",
 "title": "He / She / It",
 "subtitle": "Does she work? He does not play."
 },
 {
 "label": "Did",
 "title": "Past Tense",
 "subtitle": "Did they come? We did not see."
 }
 ]
}

{
 "title": "2. Yes/No questions",
 "sections": [
 {
 "label": "Regular verbs",
 "color": "emerald",
 "description": "For regular verbs, use <strong>do/does/did</strong> before the subject.",
 "examples": [
 {
 "en": "Do you like pizza?",
 "ua": "Do you like pizza?"
 },
 {
 "en": "Does she play tennis?",
 "ua": "Does she play tennis?"
 },
 {
 "en": "Do they watch the show?",
 "ua": "Do they watch the show?"
 }
 ]
 },
 {
 "label": "To be and modal verbs",
 "color": "sky",
 "description": "Use the pattern in the examples and focus on the highlighted words.",
 "examples": [
 {
 "en": "Are you ready?",
 "ua": "Are you ready?"
 },
 {
 "en": "Is he coming?",
 "ua": "Is he coming?"
 },
 {
 "en": "Can you swim?",
 "ua": "Can you swim?"
 },
 {
 "en": "Have you finished?",
 "ua": "Have you finished?"
 }
 ]
 }
 ]
}

{
 "title": "3. Wh-Questions",
 "sections": [
 {
 "label": "Wh-question structure",
 "color": "emerald",
 "description": "<strong>Wh-word + Auxiliary + Subject + Verb</strong> — a question word at the beginning, then an auxiliary verb.",
 "examples": [
 {
 "en": "Where do you live?",
 "ua": "Where do you live?"
 },
 {
 "en": "What did she eat?",
 "ua": "What did she eat?"
 },
 {
 "en": "Why are they running?",
 "ua": "Why are they running?"
 },
 {
 "en": "How can I help?",
 "ua": "How can I help?"
 }
 ]
 },
 {
 "label": "Wh-word as subject",
 "color": "amber",
 "description": "If <strong>Who</strong> or <strong>What</strong> is the subject, the auxiliary verb is <strong>not needed</strong>.",
 "examples": [
 {
 "en": "Who called you?",
 "ua": "Who called you?"
 },
 {
 "en": "What happened?",
 "ua": "What happened?"
 },
 {
 "en": "Who lives here?",
 "ua": "Who lives here?"
 }
 ],
 "note": "Compare: <strong>Who called you?</strong> (who is the subject) vs <strong>Who did you call?</strong> (you is the subject)."
 }
 ]
}

{
 "title": "4. Negatives",
 "sections": [
 {
 "label": "Regular verbs",
 "color": "emerald",
 "description": "Add <strong>do/does/did + not</strong> before the main verb.",
 "examples": [
 {
 "en": "I do not (don't) like apples.",
 "ua": "I do not (don't) like apples."
 },
 {
 "en": "She does not (doesn't) play football.",
 "ua": "She does not (doesn't) play football."
 },
 {
 "en": "They did not (didn't) see the movie.",
 "ua": "They did not (didn't) see the movie."
 }
 ]
 },
 {
 "label": "To be and modal verbs",
 "color": "sky",
 "description": "Add <strong>not</strong> immediately after to be or a modal verb.",
 "examples": [
 {
 "en": "He is not (isn't) ready.",
 "ua": "He is not (isn't) ready."
 },
 {
 "en": "She was not (wasn't) there.",
 "ua": "She was not (wasn't) there."
 },
 {
 "en": "You must not (mustn't) touch it.",
 "ua": "You must not (mustn't) touch it."
 },
 {
 "en": "They cannot (can't) come.",
 "ua": "They cannot (can't) come."
 }
 ]
 }
 ]
}

{
 "title": "5. Contractions",
 "intro": "In colloquial speech, not is often shortened:",
 "rows": [
 {
 "en": "do not",
 "ua": "do not",
 "note": "I don't know."
 },
 {
 "en": "does not",
 "ua": "does not",
 "note": "She doesn't like it."
 },
 {
 "en": "did not",
 "ua": "did not",
 "note": "We didn't go."
 },
 {
 "en": "is not",
 "ua": "is not",
 "note": "He isn't here."
 },
 {
 "en": "are not",
 "ua": "are not",
 "note": "They aren't coming."
 },
 {
 "en": "will not",
 "ua": "will not",
 "note": "I won't forget."
 },
 {
 "en": "can't",
 "ua": "can't",
 "note": "She can't swim. 📌 In formal writing, use full forms."
 }
 ],
 "warning": "📌 In formal writing, use full forms."
}

{
 "title": "6. Common mistakes",
 "items": [
 {
 "label": "Error 1",
 "color": "rose",
 "title": "There is no auxiliary verb in the question.",
 "wrong": "You like pizza?",
 "right": " ✅ <span class=\"font-mono\">Do you like pizza?</span> Error 2"
 },
 {
 "label": "Mistake 2",
 "color": "amber",
 "title": "No auxiliary verb in a Wh-question.",
 "wrong": "Where you live?",
 "right": "​​​​ <span class=\"font-mono\">Where do you live?</span>"
 },
 {
 "label": "Error 3",
 "color": "sky",
 "title": "Wrong choice of do/does.",
 "wrong": "She doesn't like it.",
 "right": "​​​​​​​​ apples.</span>"
 },
 {
 "label": "Mistake 4",
 "color": "purple",
 "title": "Making a negative without an auxiliary verb.",
 "wrong": "I no like apples.",
 "right": "✅ <span class=\"font-mono\">I don't like apples.</span>"
 }
 ]
}

{
 "title": "8. Practice",
 "select_title": "Exercise 1. Choose the correct option",
 "select_intro": "Choose sentences with the correct word order.",
 "selects": [
 {
 "label": "a) Do you like coffee? / b) You like coffee?",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) Where does she live? / b) Where she lives?",
 "prompt": "Which option is correct?"
 },
 {
 "label": "a) He doesn't work here. / b) He doesn't work here.",
 "prompt": "Which option is correct?"
 }
 ],
 "options": [
 "a",
 "b"
 ],
 "input_title": "Exercise 2. Construct a question",
 "input_intro": "Turn the statement into a question.",
 "inputs": [
 {
 "before": "You speak English.",
 "after": "→ Do you...?"
 },
 {
 "before": "She works in a bank.",
 "after": "→ Does she...?"
 },
 {
 "before": "They went to the party.",
 "after": "→ Did they...?"
 }
 ],
 "rephrase_title": "Exercise 3. Build negation",
 "rephrase_intro": "Turn the statement into a negation.",
 "rephrase": [
 {
 "example_label": "Example:",
 "example_original": "I like apples.",
 "example_target": "I don't like apples."
 },
 {
 "original": "1. She plays tennis.",
 "placeholder": "Write an negation"
 },
 {
 "original": "2. They watch the movie. Adverbs and adverbials",
 "placeholder": "Write your answer"
 }
 ]
}

{
 "title": "Keep learning",
 "items": [
 {
 "label": "Basic Word Order",
 "current": false
 },
 {
 "label": "Word Order in Questions and Negatives",
 "current": true
 },
 {
 "label": "Word Order with Adverbs",
 "current": false
 }
 ]
}
